6	//! CUDA stream management (RAII, host callbacks, fork/join).
7	//!
8	//! A [`CudaStream`] wraps a `CUstream` handle and ties its lifetime to its
9	//! parent [`CudaContext`]. Streams are created via
10	//! [`CudaContext::new_stream`] or [`CudaStream::fork`] and destroyed
11	//! automatically on [`Drop`].
12	//!
13	//! # Ordering model
14	//!
15	//! Operations enqueued on the same stream execute in FIFO order. Operations on
16	//! different streams may overlap. Use [`fork`](CudaStream::fork) /
17	//! [`join`](CudaStream::join) or explicit events ([`record_event`](CudaStream::record_event),
18	//! [`wait`](CudaStream::wait)) to establish cross-stream ordering.
19	//!
20	//! # Host callbacks
21	//!
22	//! [`launch_host_function`](CudaStream::launch_host_function) enqueues a
23	//! host-side closure that the driver invokes after all preceding stream work
24	//! completes. This is the primary bridge between CUDA stream completion and
25	//! Rust `async` futures.
26	
27	use crate::context::CudaContext;
28	use crate::error::{DriverError, IntoResult};
29	use crate::event::CudaEvent;
30	use std::ffi::c_void;
31	use std::mem::MaybeUninit;
32	use std::sync::Arc;
33	use std::sync::atomic::Ordering;
34	
35	/// An RAII wrapper around a `CUstream` handle.
36	///
37	/// Holds an `Arc<CudaContext>` to ensure the context outlives the stream.
38	/// A null `cu_stream` represents the per-context default stream (stream 0).
39	#[derive(Debug, PartialEq, Eq)]
40	pub struct CudaStream {
41	    /// Raw CUDA stream handle. Null for the default stream.
42	    pub(crate) cu_stream: cuda_bindings::CUstream,
43	    /// Owning context. Kept alive for the lifetime of this stream.
44	    pub(crate) ctx: Arc<CudaContext>,
45	}
46	
47	/// # Safety
48	///
49	/// `CUstream` handles are not thread-local. The CUDA driver permits enqueuing
50	/// work onto a stream from any thread, provided the owning context is bound
51	/// (which [`bind_to_thread`](CudaContext::bind_to_thread) ensures).
52	unsafe impl Send for CudaStream {}
53	/// See [`Send`] impl.
54	unsafe impl Sync for CudaStream {}
55	
56	/// Destroys the underlying `CUstream` on drop and decrements the context's
57	/// live stream count.
58	///
59	/// The default stream (null handle) is never destroyed. Errors during
60	/// teardown are recorded on the context rather than panicking.
61	impl Drop for CudaStream {
62	    fn drop(&mut self) {
63	        self.ctx.record_err(self.ctx.bind_to_thread());
64	        if !self.cu_stream.is_null() {
65	            self.ctx.num_streams.fetch_sub(1, Ordering::Relaxed);
66	            self.ctx
67	                .record_err(unsafe { cuda_bindings::cuStreamDestroy_v2(self.cu_stream).result() });
68	        }
69	    }
70	}
71	
72	impl CudaStream {
73	    /// Returns the raw `CUstream` handle (null for the default stream).
74	    pub fn cu_stream(&self) -> cuda_bindings::CUstream {
75	        self.cu_stream
76	    }
77	
78	    /// Returns the parent [`CudaContext`].
79	    pub fn context(&self) -> &Arc<CudaContext> {
80	        &self.ctx
81	    }
82	
83	    /// Blocks the calling thread until all work enqueued on this stream
84	    /// completes.
85	    pub fn synchronize(&self) -> Result<(), DriverError> {
86	        self.ctx.bind_to_thread()?;
87	        unsafe { cuda_bindings::cuStreamSynchronize(self.cu_stream) }.result()
88	    }
89	
90	    /// Creates a new non-blocking stream that waits on all prior work in
91	    /// `self` before executing its own.
92	    ///
93	    /// Semantically equivalent to creating a new stream and calling
94	    /// [`join`](Self::join) on it with `self`, establishing a fork point
95	    /// in the stream DAG.
96	    pub fn fork(&self) -> Result<Arc<Self>, DriverError> {
97	        self.ctx.bind_to_thread()?;
98	        self.ctx.num_streams.fetch_add(1, Ordering::Relaxed);
99	        let mut cu_stream = MaybeUninit::uninit();
100	        let cu_stream = unsafe {
101	            cuda_bindings::cuStreamCreate(
102	                cu_stream.as_mut_ptr(),
103	                cuda_bindings::CUstream_flags_enum_CU_STREAM_NON_BLOCKING,
104	            )
105	            .result()?;
106	            cu_stream.assume_init()
107	        };
108	        let stream = Arc::new(CudaStream {
109	            cu_stream,
110	            ctx: self.ctx.clone(),
111	        });
112	        stream.join(self)?;
113	        Ok(stream)
114	    }
115	
116	    /// Makes `self` wait on all prior work in `other`.
117	    ///
118	    /// Records an event on `other` and enqueues a wait on `self`. This is the
119	    /// join side of the fork/join pattern: after this call, work enqueued on
120	    /// `self` is guaranteed to observe all side effects of prior work on
121	    /// `other`.
122	    pub fn join(&self, other: &CudaStream) -> Result<(), DriverError> {
123	        self.wait(&other.record_event(None)?)
124	    }
125	
126	    /// Records an event on this stream and returns it.
127	    ///
128	    /// `flags` defaults to `CU_EVENT_DISABLE_TIMING` when `None`, which is
129	    /// cheaper than a timing-enabled event. Pass
130	    /// `Some(CU_EVENT_DEFAULT)` if you need [`CudaEvent::elapsed_ms`].
131	    pub fn record_event(
132	        &self,
133	        flags: Option<cuda_bindings::CUevent_flags>,
134	    ) -> Result<CudaEvent, DriverError> {
135	        let event = self.ctx.new_event(flags)?;
136	        event.record(self)?;
137	        Ok(event)
138	    }
139	
140	    /// Enqueues a wait on `event` into this stream.
141	    ///
142	    /// All work enqueued on `self` after this call will not begin until
143	    /// `event` has been recorded (i.e., all prior work on the stream that
144	    /// recorded `event` has completed).
145	    pub fn wait(&self, event: &CudaEvent) -> Result<(), DriverError> {
146	        self.ctx.bind_to_thread()?;
147	        unsafe {
148	            cuda_bindings::cuStreamWaitEvent(
149	                self.cu_stream,
150	                event.cu_event(),
151	                cuda_bindings::CUevent_wait_flags_enum_CU_EVENT_WAIT_DEFAULT,
152	            )
153	            .result()
154	        }
155	    }
156	
157	    /// Enqueues a host-side callback that the driver invokes after all prior
158	    /// work on this stream completes.
159	    ///
160	    /// This is the bridge between CUDA stream ordering and Rust async: wrap a
161	    /// `oneshot::Sender::send` or `Waker::wake` in `host_func` to unblock a
162	    /// future when GPU work finishes.
163	    ///
164	    /// `host_func` is boxed, leaked into a raw pointer, and passed as user
165	    /// data to `cuLaunchHostFunc`. The driver calls
166	    /// `callback_wrapper` on a driver-internal
167	    /// thread, which reclaims the box and invokes the closure.
168	    ///
169	    /// Panics inside the closure are caught and discarded to prevent unwinding
170	    /// across the FFI boundary.
171	    pub fn launch_host_function<F: FnOnce() + Send>(
172	        &self,
173	        host_func: F,
174	    ) -> Result<(), DriverError> {
175	        let boxed = Box::new(host_func);
176	        unsafe {
177	            cuda_bindings::cuLaunchHostFunc(
178	                self.cu_stream,
179	                Some(Self::callback_wrapper::<F>),
180	                Box::into_raw(boxed) as *mut c_void,
181	            )
182	            .result()
183	        }
184	    }
185	
186	    /// `extern "C"` trampoline invoked by the CUDA driver on a driver-internal
187	    /// thread when a host function callback fires.
188	    ///
189	    /// Reconstructs the `Box<F>` from the raw pointer and calls the closure.
190	    /// Panics are caught with `catch_unwind` to prevent unwinding across the
191	    /// C ABI boundary.
192	    ///
193	    /// # Safety
194	    ///
195	    /// - `callback` must be a pointer produced by `Box::into_raw(Box::new(f))`
196	    ///   where `f: F`.
197	    /// - Must be called exactly once per enqueued callback (double-free
198	    ///   otherwise).
199	    unsafe extern "C" fn callback_wrapper<F: FnOnce() + Send>(callback: *mut c_void) {
200	        let _ = std::panic::catch_unwind(|| {
201	            let callback: Box<F> = unsafe { Box::from_raw(callback as *mut F) };
202	            callback();
203	        });
204	    }
205	}
