6	//! Stream scheduling policies that control how [`DeviceOperation`]s are
7	//! assigned to CUDA streams.
8	//!
9	//! A [`SchedulingPolicy`] decouples operation construction from stream
10	//! selection. The policy chooses a stream when an operation is scheduled or
11	//! executed synchronously, enabling transparent overlap of independent work.
12	//!
13	//! | Policy                   | Behaviour                                    |
14	//! |--------------------------|----------------------------------------------|
15	//! | [`StreamPoolRoundRobin`] | Rotates across *N* streams for HW overlap    |
16	//! | [`SingleStream`]         | Serialises all work onto one stream          |
17	//!
18	//! [`DeviceOperation`]: crate::device_operation::DeviceOperation
19	
20	use crate::device_future::DeviceFuture;
21	use crate::device_operation::{DeviceOperation, ExecutionContext};
22	use crate::error::{DeviceError, device_error};
23	use cuda_core::{CudaContext, CudaStream};
24	use std::sync::Arc;
25	use std::sync::atomic::AtomicUsize;
26	
27	/// Top-level enum wrapping all supported scheduling policy implementations.
28	///
29	/// Used as the concrete policy type stored in
30	/// [`AsyncDeviceContext`](crate::device_context::AsyncDeviceContext).
31	pub enum GlobalSchedulingPolicy {
32	    /// Round-robin across a pool of CUDA streams.
33	    RoundRobin(StreamPoolRoundRobin),
34	}
35	
36	impl GlobalSchedulingPolicy {
37	    /// Returns a reference to the inner policy as a trait object.
38	    pub fn as_scheduling_policy(&self) -> Result<&impl SchedulingPolicy, DeviceError> {
39	        match self {
40	            GlobalSchedulingPolicy::RoundRobin(rr) => Ok(rr),
41	        }
42	    }
43	}
44	
45	/// Delegates to the inner policy variant.
46	impl SchedulingPolicy for GlobalSchedulingPolicy {
47	    fn init(&mut self, ctx: &Arc<CudaContext>) -> Result<(), DeviceError> {
48	        match self {
49	            GlobalSchedulingPolicy::RoundRobin(rr) => rr.init(ctx),
50	        }
51	    }
52	    fn schedule<T: Send, O: DeviceOperation<Output = T>>(
53	        &self,
54	        op: O,
55	    ) -> Result<DeviceFuture<T, O>, DeviceError> {
56	        match self {
57	            GlobalSchedulingPolicy::RoundRobin(rr) => rr.schedule(op),
58	        }
59	    }
60	    fn sync<T: Send, O: DeviceOperation<Output = T>>(&self, op: O) -> Result<T, DeviceError> {
61	        match self {
62	            GlobalSchedulingPolicy::RoundRobin(rr) => rr.sync(op),
63	        }
64	    }
65	}
66	
67	/// `Arc`-wrapped policy delegates scheduling but rejects re-initialization,
68	/// since the inner data cannot be mutated through an `Arc`.
69	impl SchedulingPolicy for Arc<GlobalSchedulingPolicy> {
70	    fn init(&mut self, _ctx: &Arc<CudaContext>) -> Result<(), DeviceError> {
71	        Err(DeviceError::Scheduling(
72	            "Cannot initialize scheduling policy inside an Arc.".to_string(),
73	        ))
74	    }
75	    fn schedule<T: Send, O: DeviceOperation<Output = T>>(
76	        &self,
77	        op: O,
78	    ) -> Result<DeviceFuture<T, O>, DeviceError> {
79	        match self.as_ref() {
80	            GlobalSchedulingPolicy::RoundRobin(rr) => rr.schedule(op),
81	        }
82	    }
83	    fn sync<T: Send, O: DeviceOperation<Output = T>>(&self, op: O) -> Result<T, DeviceError> {
84	        match self.as_ref() {
85	            GlobalSchedulingPolicy::RoundRobin(rr) => rr.sync(op),
86	        }
87	    }
88	}
