6	//! Owned and borrowed wrappers around CUDA device pointers.
7	//!
8	//! [`DevicePointer`] is a thin, `Copy` handle to device memory suitable for
9	//! passing as a kernel argument. [`DeviceBox`] owns device memory and frees it
10	//! asynchronously through a dedicated deallocator stream on drop.
11	//!
12	//! # Async deallocation
13	//!
14	//! [`DeviceBox`] enqueues `cuMemFreeAsync` on a per-device deallocator stream
15	//! rather than blocking with `cuMemFree`. Callers **must** synchronize all
16	//! streams that reference the allocation before dropping the box.
17	
18	use crate::device_context::with_deallocator_stream;
19	use crate::error::DeviceError;
20	use crate::launch::{AsyncKernelLaunch, KernelArgument};
21	use cuda_bindings::CUdeviceptr;
22	use cuda_core::memory::free_async;
23	use std::io::{self, Write};
24	use std::marker::PhantomData;
25	
26	/// Non-owning, `Copy` handle to a typed device allocation.
27	///
28	/// Does not manage lifetime -- the underlying memory must outlive all uses.
29	#[derive(Debug, Copy, Clone)]
30	pub struct DevicePointer<T> {
31	    /// Ties the pointer to element type `T` without owning one.
32	    _marker: PhantomData<T>,
33	    /// Raw CUDA device pointer.
34	    pub dptr: CUdeviceptr,
35	}
36	
37	/// # Safety
38	///
39	/// `DevicePointer` is a plain integer handle with no thread-affine state.
40	/// Sending it across threads does not violate CUDA's driver API contract.
41	unsafe impl<T> Send for DevicePointer<T> {}
42	
43	impl<T> DevicePointer<T> {
44	    /// Returns the raw [`CUdeviceptr`].
45	    pub fn cu_deviceptr(&self) -> CUdeviceptr {
46	        self.dptr
47	    }
48	}
49	
50	/// Pushes the underlying device address as a kernel argument.
51	impl<T: Send + Sized> KernelArgument for DevicePointer<T> {
52	    fn push_arg(self, launcher: &mut AsyncKernelLaunch<'_>) {
53	        launcher.push_arg(self.cu_deviceptr());
54	    }
55	}
56	
57	/// Owning wrapper around a device allocation that frees memory asynchronously
58	/// on drop.
59	///
60	/// `DeviceBox<[DType]>` represents a contiguous device buffer of `len`
61	/// elements. The allocation is freed via `cuMemFreeAsync` on the device's
62	/// deallocator stream when the box is dropped.
63	///
64	/// # Safety contract
65	///
66	/// All streams that reference this allocation **must** be synchronized before
67	/// the box is dropped. Violating this causes use-after-free on the device.
68	#[derive(Debug)]
69	pub struct DeviceBox<T: Send + ?Sized> {
70	    /// Ordinal of the device that owns this allocation.
71	    device_id: usize,
72	    /// Raw CUDA device pointer to the start of the allocation.
73	    cudptr: CUdeviceptr,
74	    /// Number of elements (not bytes) in the allocation.
75	    len: usize,
76	    /// Ties the box to the element type.
77	    _marker: PhantomData<T>,
78	}
79	
80	/// # Safety
81	///
82	/// Device pointers are plain integers. The CUDA driver API is thread-safe for
83	/// distinct streams, and `DeviceBox` holds no thread-affine state.
84	unsafe impl<T: Send + ?Sized> Send for DeviceBox<T> {}
85	
86	/// # Safety
87	///
88	/// See the [`Send`] impl. Shared references only expose the device pointer
89	/// value, which is safe to read from any thread.
90	unsafe impl<T: Send + ?Sized> Sync for DeviceBox<T> {}
91	
92	/// Best-effort enqueue of an asynchronous free on the device's deallocator
93	/// stream.
94	///
95	/// Drop cannot return errors, so failures to access the deallocator stream or
96	/// enqueue the free are reported to stderr instead of panicking.
97	impl<T: Send + ?Sized> Drop for DeviceBox<T> {
98	    fn drop(&mut self) {
99	        let result = unsafe {
100	            with_deallocator_stream(self.device_id, |stream| {
101	                free_async(self.cudptr, stream.cu_stream()).map_err(DeviceError::Driver)
102	            })
103	        };
104	
105	        match result {
106	            Ok(Ok(())) => {}
107	            Ok(Err(err)) | Err(err) => {
108	                let mut stderr = io::stderr().lock();
109	                let _ = writeln!(
110	                    stderr,
111	                    "cuda-async: failed to enqueue async free for device pointer on device_id={}: {}",
112	                    self.device_id, err
113	                );
114	            }
115	        }
116	    }
117	}
118	
119	impl<DType: Send + Sized> DeviceBox<[DType]> {
120	    /// Constructs a `DeviceBox<[DType]>` from a raw device pointer, element
121	    /// count, and device ordinal.
122	    ///
123	    /// # Safety
124	    ///
125	    /// * `dptr` must point to a valid device allocation of at least
126	    ///   `len * size_of::<DType>()` bytes on device `device_id`.
127	    /// * Ownership of the allocation transfers to the returned `DeviceBox`.
128	    pub unsafe fn from_raw_parts(dptr: CUdeviceptr, len: usize, device_id: usize) -> Self {
129	        Self {
130	            _marker: PhantomData,
131	            cudptr: dptr,
132	            len,
133	            device_id,
134	        }
135	    }
136	
137	    /// Returns `true` if the buffer contains zero elements.
138	    pub fn is_empty(&self) -> bool {
139	        self.len == 0
140	    }
141	
142	    /// Returns the number of elements in the buffer.
143	    pub fn len(&self) -> usize {
144	        self.len
145	    }
146	
147	    /// Returns the raw [`CUdeviceptr`].
148	    pub fn cu_deviceptr(&self) -> CUdeviceptr {
149	        self.cudptr
150	    }
151	
152	    /// Returns the ordinal of the device that owns this allocation.
153	    pub fn device_id(&self) -> usize {
154	        self.device_id
155	    }
156	
157	    /// Creates a non-owning [`DevicePointer`] into this allocation.
158	    pub fn device_pointer(&self) -> DevicePointer<DType> {
159	        DevicePointer {
160	            _marker: PhantomData,
161	            dptr: self.cudptr,
162	        }
163	    }
164	}
