285	/// State-machine implementation of [`Future`] for CUDA device work.
286	///
287	/// | State       | Action on poll                                          |
288	/// |-------------|---------------------------------------------------------|
289	/// | `Failed`    | Immediately returns `Err`.                              |
290	/// | `Idle`      | Executes the operation, registers callback, -> Pending. |
291	/// | `Executing` | Checks callback flag; returns result if done.           |
292	/// | `Complete`  | Panics -- must not poll after completion.               |
293	impl<T: Send + 'static, DO: DeviceOperation<Output = T>> Future for DeviceFuture<T, DO> {
294	    type Output = Result<T, DeviceError>;
295	    fn poll(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
296	        // Opportunistically reclaim cancelled results whose GPU work has
297	        // completed. Cheap when nothing is parked (one atomic load).
298	        reclaim::sweep();
299	
300	        if self.state == DeviceFutureState::Failed {
301	            self.state = DeviceFutureState::Complete;
302	            let error = self
303	                .error
304	                .take()
305	                .expect("Failed state must carry an error.");
306	            return Poll::Ready(Err(error));
307	        }
308	
309	        if self.callback_state.is_none() {
310	            self.callback_state = Some(Arc::new(StreamCallbackState::new()));
311	        }
312	        let waker_state = self
313	            .callback_state
314	            .as_ref()
315	            .map(Arc::clone)
316	            .expect("Impossible.");
317	
318	        match self.state {
319	            DeviceFutureState::Idle => {
320	                waker_state.waker.register(cx.waker());
321	                if let Err(e) = self.execute() {
322	                    self.state = DeviceFutureState::Complete;
323	                    return Poll::Ready(Err(e));
324	                }
325	                if let Err(e) = unsafe { self.register_callback(Arc::clone(&waker_state)) } {
326	                    self.state = DeviceFutureState::Complete;
327	                    // The launch already succeeded, so GPU work is in flight
328	                    // and `result` holds the owned resources. Route them
329	                    // through deferred reclamation instead of leaving them
330	                    // for an immediate drop while the kernel may still run
331	                    // (issue #99, callback-registration-failure path).
332	                    self.reclaim_in_flight_result();
333	                    return Poll::Ready(Err(e));
334	                }
335	                self.state = DeviceFutureState::Executing;
336	                Poll::Pending
337	            }
338	            DeviceFutureState::Executing => {
339	                if waker_state.complete.load(Ordering::Relaxed) {
340	                    self.state = DeviceFutureState::Complete;
341	                    return Poll::Ready(Ok(self.result.take().expect("Expected result.")));
342	                }
343	                waker_state.waker.register(cx.waker());
344	                if waker_state.complete.load(Ordering::Relaxed) {
345	                    self.state = DeviceFutureState::Complete;
346	                    Poll::Ready(Ok(self.result.take().expect("Expected result.")))
347	                } else {
348	                    Poll::Pending
349	                }
350	            }
351	            DeviceFutureState::Complete => panic!("Poll called after completion."),
352	            DeviceFutureState::Failed => unreachable!(),
353	        }
354	    }
355	}
