364	
365	    #[derive(Clone)]
366	    struct DropTracker {
367	        events: Arc<Mutex<Vec<&'static str>>>,
368	    }
369	
370	    impl Drop for DropTracker {
371	        fn drop(&mut self) {
372	            self.events.lock().unwrap().push("drop");
373	        }
374	    }
375	
376	    #[test]
377	    fn cleanup_executing_result_synchronizes_before_drop() {
378	        let events = Arc::new(Mutex::new(Vec::new()));
379	        let tracker = DropTracker {
380	            events: Arc::clone(&events),
381	        };
382	        let mut future: DeviceFuture<DropTracker, Value<DropTracker>> = DeviceFuture {
383	            device_operation: None,
384	            execution_context: None,
385	            result: Some(tracker),
386	            error: None,
387	            state: DeviceFutureState::Executing,
388	            callback_state: None,
389	        };
390	
391	        future.cleanup_executing_result_with(|| {
392	            events.lock().unwrap().push("sync");
393	            Ok(())
394	        });
395	
396	        assert_eq!(events.lock().unwrap().as_slice(), ["sync", "drop"]);
397	        assert!(future.result.is_none());
398	    }
399	
400	    #[test]
401	    fn cleanup_executing_result_leaks_when_synchronize_fails() {
402	        let drops = Arc::new(AtomicUsize::new(0));
403	
404	        struct CountDrop(Arc<AtomicUsize>);
405	
406	        impl Drop for CountDrop {
407	            fn drop(&mut self) {
408	                self.0.fetch_add(1, Ordering::Relaxed);
409	            }
410	        }
411	
412	        let mut future: DeviceFuture<CountDrop, Value<CountDrop>> = DeviceFuture {
413	            device_operation: None,
414	            execution_context: None,
415	            result: Some(CountDrop(Arc::clone(&drops))),
416	            error: None,
417	            state: DeviceFutureState::Executing,
418	            callback_state: None,
419	        };
420	
421	        future.cleanup_executing_result_with(|| Err(DeviceError::Internal("boom".to_string())));
422	
423	        assert_eq!(drops.load(Ordering::Relaxed), 0);
424	        assert!(future.result.is_none());
425	    }
426	
427	    /// The shape left behind by issue #99's second path: `execute()`
428	    /// succeeded (GPU work submitted, `result` populated) but
429	    /// `register_callback()` failed, so poll flipped the state to
430	    /// `Complete` with the result still stored. Cleanup must treat that
431	    /// exactly like a cancelled `Executing` future.
432	    #[test]
433	    fn cleanup_covers_complete_future_left_by_callback_registration_failure() {
434	        let events = Arc::new(Mutex::new(Vec::new()));
435	        let tracker = DropTracker {
436	            events: Arc::clone(&events),
437	        };
438	        let mut future: DeviceFuture<DropTracker, Value<DropTracker>> = DeviceFuture {
439	            device_operation: None,
440	            execution_context: None,
441	            result: Some(tracker),
442	            error: None,
443	            state: DeviceFutureState::Complete,
444	            callback_state: None,
445	        };
446	
447	        assert!(future.has_undelivered_submission());
448	        future.cleanup_executing_result_with(|| {
449	            events.lock().unwrap().push("sync");
450	            Ok(())
451	        });
452	
453	        assert_eq!(events.lock().unwrap().as_slice(), ["sync", "drop"]);
454	        assert!(future.result.is_none());
455	        assert!(!future.has_undelivered_submission());
456	    }
