458	    /// A `Complete` future whose result was already delivered to the caller
459	    /// has nothing to reclaim.
460	    #[test]
461	    fn cleanup_is_noop_after_result_delivery() {
462	        let mut future: DeviceFuture<u32, Value<u32>> = DeviceFuture {
463	            device_operation: None,
464	            execution_context: None,
465	            result: None,
466	            error: None,
