478	    #[test]
479	    fn cleanup_is_noop_for_idle_future() {
480	        let drops = Arc::new(AtomicUsize::new(0));
481	
482	        struct CountDrop(Arc<AtomicUsize>);
483	
484	        impl Drop for CountDrop {
485	            fn drop(&mut self) {
486	                self.0.fetch_add(1, Ordering::Relaxed);
487	            }
488	        }
489	
490	        let mut future: DeviceFuture<CountDrop, Value<CountDrop>> = DeviceFuture {
491	            device_operation: None,
492	            execution_context: None,
493	            result: Some(CountDrop(Arc::clone(&drops))),
494	            error: None,
495	            state: DeviceFutureState::Idle,
