57	impl ExecutionContext {
58	    /// Constructs a context from a stream, deriving the device and CUDA context
59	    /// from the stream's owning context.
60	    pub fn new(cuda_stream: Arc<CudaStream>) -> Self {
61	        let cuda_context = Arc::clone(cuda_stream.context());
62	        let device = cuda_context.ordinal();
63	        Self {
64	            cuda_stream,
65	            cuda_context,
66	            device,
67	        }
68	    }
