86	/// A lazy, composable GPU operation that may be executed synchronously or
87	/// asynchronously.
88	///
89	/// `DeviceOperation` is the core trait of the `cuda-async` crate. It
90	/// represents a unit of GPU work that is **stream-agnostic**: the concrete
91	/// CUDA stream is chosen only at scheduling time, not at construction time.
92	///
93	/// # Composing operations
94	///
95	/// Combinators build complex dataflow graphs without touching streams:
96	///
97	/// | Combinator                | Effect                                          |
98	/// |---------------------------|-------------------------------------------------|
99	/// | [`and_then`]              | Sequence: `A` then `f(result_a)`.               |
100	/// | [`and_then_with_context`] | Like `and_then` but the closure sees the stream.|
101	/// | [`apply`]                 | Alias for `and_then`.                           |
102	/// | [`arc`]                   | Wraps the output in `Arc<T>`.                   |
103	/// | [`zip!`]                  | Runs two or three operations, returns a tuple.  |
104	/// | [`unzip!`]                | Splits a tuple-producing operation.             |
105	///
106	/// # Executing operations
107	///
108	/// | Method       | Picks stream via         | Blocks? | Async? |
109	/// |--------------|--------------------------|---------|--------|
110	/// | [`schedule`] | `SchedulingPolicy`       | No      | Yes    |
111	/// | `.await`     | Default policy           | No      | Yes    |
112	/// | [`sync`]     | Default policy           | Yes     | No     |
113	/// | [`sync_on`]  | Caller-provided stream   | Yes     | No     |
114	/// | [`async_on`] | Caller-provided stream   | No      | No     |
115	///
116	/// # Implementors
117	///
118	/// Implement [`execute`] to describe the GPU work. The blanket [`IntoFuture`]
119	/// impl must also be provided (typically via the same boilerplate that
120	/// delegates to `with_default_device_policy`).
121	///
122	/// [`and_then`]: DeviceOperation::and_then
123	/// [`and_then_with_context`]: DeviceOperation::and_then_with_context
124	/// [`apply`]: DeviceOperation::apply
125	/// [`arc`]: DeviceOperation::arc
126	/// [`zip!`]: crate::zip
127	/// [`unzip!`]: crate::unzip
128	/// [`schedule`]: DeviceOperation::schedule
129	/// [`sync`]: DeviceOperation::sync
130	/// [`sync_on`]: DeviceOperation::sync_on
131	/// [`async_on`]: DeviceOperation::async_on
132	/// [`execute`]: DeviceOperation::execute
133	pub trait DeviceOperation:
134	    Send + Sized + IntoFuture<Output = Result<<Self as DeviceOperation>::Output, DeviceError>>
135	{
136	    /// The value produced when the operation completes successfully.
137	    ///
138	    /// The `'static` bound exists because a cancelled in-flight result is
139	    /// parked in the [`reclaim`](crate::reclaim) limbo and dropped only
140	    /// after the GPU work completes, which can be after any non-`'static`
141	    /// borrow it carries would have expired.
142	    type Output: Send + 'static;
143	
144	    /// Submits GPU work to the stream in `context` and returns the result.
145	    ///
146	    /// # Safety
147	    ///
148	    /// GPU work may still be in flight when this returns. The caller must
149	    /// synchronize the stream before reading device-side outputs.
150	    unsafe fn execute(
151	        self,
152	        context: &ExecutionContext,
153	    ) -> Result<<Self as DeviceOperation>::Output, DeviceError>;
154	
155	    /// Pairs this operation with a stream chosen by `policy` and returns a
156	    /// [`DeviceFuture`] that can be `.await`-ed.
157	    fn schedule<P: SchedulingPolicy>(
158	        self,
159	        policy: &P,
160	    ) -> Result<DeviceFuture<<Self as DeviceOperation>::Output, Self>, DeviceError> {
161	        policy.schedule(self)
162	    }
163	
164	    /// Chains a dependent operation: executes `self`, then passes its output
165	    /// to `f` to produce the next operation.
166	    fn and_then<O: Send, DO, F>(
167	        self,
168	        f: F,
169	    ) -> AndThen<<Self as DeviceOperation>::Output, Self, O, DO, F>
170	    where
171	        DO: DeviceOperation<Output = O>,
172	        F: FnOnce(<Self as DeviceOperation>::Output) -> DO,
173	    {
174	        AndThen {
175	            op: self,
176	            closure: f,
177	        }
178	    }
179	
180	    /// Like [`and_then`](Self::and_then), but the closure also receives the
181	    /// [`ExecutionContext`] so it can inspect the stream or device.
182	    fn and_then_with_context<O: Send, DO, F>(
183	        self,
184	        f: F,
185	    ) -> AndThenWithContext<<Self as DeviceOperation>::Output, Self, O, DO, F>
186	    where
187	        DO: DeviceOperation<Output = O>,
188	        F: FnOnce(&ExecutionContext, <Self as DeviceOperation>::Output) -> DO,
189	    {
190	        AndThenWithContext {
191	            op: self,
192	            closure: f,
193	        }
194	    }
195	
196	    /// Wraps the output in an [`Arc`], useful when the result must be shared
197	    /// across multiple consumers.
198	    fn arc(self) -> DeviceOperationArc<<Self as DeviceOperation>::Output, Self>
199	    where
200	        <Self as DeviceOperation>::Output: Sync,
201	    {
202	        DeviceOperationArc { op: self }
203	    }
204	
205	    /// Alias for [`and_then`](Self::and_then).
206	    fn apply<O: Send, DO, F>(
207	        self,
208	        f: F,
209	    ) -> AndThen<<Self as DeviceOperation>::Output, Self, O, DO, F>
210	    where
211	        DO: DeviceOperation<Output = O>,
212	        F: FnOnce(<Self as DeviceOperation>::Output) -> DO,
213	    {
214	        self.and_then(f)
215	    }
216	
217	    /// Executes the operation synchronously on the default device using the
218	    /// thread-local scheduling policy. Blocks until the stream is idle.
219	    fn sync(self) -> Result<<Self as DeviceOperation>::Output, DeviceError> {
220	        with_default_device_policy(|policy| policy.sync(self))?
221	    }
222	
223	    /// Executes the operation on `stream` **without** synchronizing.
224	    ///
225	    /// # Safety
226	    ///
227	    /// GPU work may still be in flight when this returns. The caller must
228	    /// synchronize `stream` before consuming device-side outputs.
229	    unsafe fn async_on(
230	        self,
231	        stream: &Arc<CudaStream>,
232	    ) -> Result<<Self as DeviceOperation>::Output, DeviceError> {
233	        let ctx = ExecutionContext::new(Arc::clone(stream));
234	        unsafe { self.execute(&ctx) }
235	    }
236	
237	    /// Executes the operation on `stream` and synchronizes before returning.
238	    fn sync_on(
239	        self,
240	        stream: &Arc<CudaStream>,
241	    ) -> Result<<Self as DeviceOperation>::Output, DeviceError> {
242	        let ctx = ExecutionContext::new(Arc::clone(stream));
243	        let res = unsafe { self.execute(&ctx) };
244	        finish_sync(res, stream.synchronize())
245	    }
246	}
247	
248	fn finish_sync<T>(
249	    operation_result: Result<T, DeviceError>,
250	    synchronize_result: Result<(), cuda_core::DriverError>,
251	) -> Result<T, DeviceError> {
252	    let output = operation_result?;
253	    synchronize_result.map_err(DeviceError::Driver)?;
254	    Ok(output)
255	}
