259	/// Wraps a [`DeviceOperation`] whose output is `Arc`-wrapped.
260	///
261	/// Produced by [`DeviceOperation::arc`].
262	pub struct DeviceOperationArc<I: Send + Sync, DI: DeviceOperation<Output = I>> {
263	    /// The inner operation whose result will be wrapped in [`Arc`].
264	    op: DI,
265	}
266	
267	/// # Safety
268	///
269	/// `DI` is `Send` (required by `DeviceOperation`), and `I: Send + Sync`
270	/// ensures the `Arc<I>` output is safe to transfer.
271	unsafe impl<I: Send + Sync, DI: DeviceOperation<Output = I>> Send for DeviceOperationArc<I, DI> {}
272	
273	/// Executes the inner operation and wraps the result in [`Arc`].
274	impl<I: Send + Sync + 'static, DI: DeviceOperation<Output = I>> DeviceOperation
275	    for DeviceOperationArc<I, DI>
276	{
277	    type Output = Arc<I>;
278	
279	    unsafe fn execute(self, context: &ExecutionContext) -> Result<Arc<I>, DeviceError> {
280	        unsafe {
281	            let val = self.op.execute(context)?;
282	            Ok(Arc::new(val))
283	        }
284	    }
285	}
286	
287	/// Schedules via the thread-local default policy.
288	impl<I: Send + Sync + 'static, DI: DeviceOperation<Output = I>> IntoFuture
289	    for DeviceOperationArc<I, DI>
290	{
291	    type Output = Result<Arc<I>, DeviceError>;
292	    type IntoFuture = DeviceFuture<Arc<I>, DeviceOperationArc<I, DI>>;
293	    fn into_future(self) -> Self::IntoFuture {
294	        match with_default_device_policy(|policy| policy.schedule(self)) {
295	            Ok(Ok(future)) => future,
296	            Ok(Err(e)) | Err(e) => DeviceFuture::failed(e),
297	        }
298	    }
299	}
