317	/// # Safety
318	///
319	/// Both `DI` and `F` are `Send`. The struct owns them exclusively, so
320	/// transferring across threads is safe.
321	unsafe impl<I: Send, DI, O: Send, DO, F> Send for AndThen<I, DI, O, DO, F>
322	where
323	    DI: DeviceOperation<Output = I>,
324	    DO: DeviceOperation<Output = O>,
325	    F: FnOnce(I) -> DO + Send,
326	{
327	}
