329	/// Executes the first operation, feeds its result to the closure, then
330	/// executes the resulting second operation on the same stream.
331	impl<I: Send, DI, O: Send + 'static, DO, F> DeviceOperation for AndThen<I, DI, O, DO, F>
332	where
333	    DI: DeviceOperation<Output = I>,
334	    DO: DeviceOperation<Output = O>,
335	    F: FnOnce(I) -> DO + Send,
336	{
337	    type Output = O;
338	
339	    unsafe fn execute(self, context: &ExecutionContext) -> Result<O, DeviceError> {
340	        unsafe {
341	            let input = self.op.execute(context)?;
342	            let output_op = (self.closure)(input);
343	            output_op.execute(context)
344	        }
345	    }
346	}
