355	    type Output = Result<O, DeviceError>;
356	    type IntoFuture = DeviceFuture<O, AndThen<I, DI, O, DO, F>>;
357	    fn into_future(self) -> Self::IntoFuture {
358	        match with_default_device_policy(|policy| policy.schedule(self)) {
359	            Ok(Ok(future)) => future,
360	            Ok(Err(e)) | Err(e) => DeviceFuture::failed(e),
361	        }
362	    }
