392	/// Executes the first operation, then passes `(context, result)` to the
393	/// closure and executes the resulting second operation.
394	impl<I: Send, DI, O: Send + 'static, DO, F> DeviceOperation for AndThenWithContext<I, DI, O, DO, F>
395	where
396	    DI: DeviceOperation<Output = I>,
