118	/// A small, immutable set of ahead-of-time compiled kernel variants.
119	///
120	/// `N` is part of the type so library authors can expose a bounded menu of
121	/// supported kernels without runtime registration or JIT compilation.
122	/// Automatic candidate filtering uses a fixed stack array and does not
123	/// allocate.
124	#[derive(Clone, Debug, PartialEq, Eq)]
125	pub struct KernelFamily<Id, Entry, Meta, const N: usize> {
126	    id: KernelFamilyId,
127	    variants: [KernelVariant<Id, Entry, Meta>; N],
128	}
