130	impl<Id: Eq, Entry, Meta, const N: usize> KernelFamily<Id, Entry, Meta, N> {
131	    /// Creates a validated family.
132	    ///
133	    /// Variant IDs must be stable semantic values. Array indices, pointers,
134	    /// `TypeId`s, and formatted debug strings are not stable cache identities.
135	    pub fn try_new(
136	        name: &'static str,
137	        revision: u32,
138	        variants: [KernelVariant<Id, Entry, Meta>; N],
139	    ) -> Result<Self, KernelFamilyBuildError> {
140	        if N == 0 {
141	            return Err(KernelFamilyBuildError::EmptyFamily);
142	        }
143	        if name.trim().is_empty() {
144	            return Err(KernelFamilyBuildError::EmptyFamilyName);
145	        }
146	
147	        for duplicate_index in 1..N {
148	            if let Some(first_index) = (0..duplicate_index)
149	                .find(|&first_index| variants[first_index].id == variants[duplicate_index].id)
150	            {
151	                return Err(KernelFamilyBuildError::DuplicateVariantId {
152	                    first_index,
153	                    duplicate_index,
154	                });
155	            }
156	        }
157	
158	        Ok(Self {
159	            id: KernelFamilyId { name, revision },
160	            variants,
161	        })
162	    }
