169	    /// Variants in declaration order.
170	    pub const fn variants(&self) -> &[KernelVariant<Id, Entry, Meta>; N] {
171	        &self.variants
172	    }
173	
174	    /// Looks up a variant by stable ID.
175	    pub fn get(&self, id: &Id) -> Option<&KernelVariant<Id, Entry, Meta>> {
176	        self.variants.iter().find(|variant| variant.id() == id)
177	    }
178	}
