243	        problem: &Problem,
244	    ) -> Result<Option<Id>, Self::Error>;
245	
246	    /// Stores a selector result after the family has revalidated it.
247	    fn store(
248	        &mut self,
249	        family: KernelFamilyId,
250	        problem: &Problem,
251	        variant: &Id,
252	    ) -> Result<(), Self::Error>;
253	}
