399	/// Result type returned by [`KernelFamily::select`].
400	pub type KernelSelectionResult<'family, Id, Entry, Meta, Problem, Selector, Cache> = Result<
401	    SelectedVariant<'family, Id, Entry, Meta>,
402	    KernelSelectionError<
403	        Id,
404	        <Problem as KernelProblem<KernelVariant<Id, Entry, Meta>>>::Rejection,
405	        <Selector as KernelSelector<Problem, KernelVariant<Id, Entry, Meta>, Id>>::Error,
406	        <Cache as KernelSelectionCache<Problem, Id>>::Error,
407	    >,
408	>;
409	
410	impl<Id, Entry, Meta, const N: usize> KernelFamily<Id, Entry, Meta, N>
411	where
412	    Id: Eq + fmt::Debug,
413	{
414	    /// Selects a valid variant with explicit provenance.
415	    ///
416	    /// `Force` bypasses both cache and selector. `Auto` validates cache hits,
417	    /// treats stale/unknown/ineligible IDs as misses, then gives the selector
418	    /// only eligible variants. Selector output is checked again before storage.
419	    pub fn select<'family, Problem, Selector, Cache>(
420	        &'family self,
421	        problem: &Problem,
422	        mode: SelectionMode<Id>,
423	        selector: &mut Selector,
424	        cache: &mut Cache,
425	    ) -> KernelSelectionResult<'family, Id, Entry, Meta, Problem, Selector, Cache>
426	    where
427	        Problem: KernelProblem<KernelVariant<Id, Entry, Meta>>,
428	        Selector: KernelSelector<Problem, KernelVariant<Id, Entry, Meta>, Id>,
429	        Cache: KernelSelectionCache<Problem, Id>,
430	    {
431	        if let SelectionMode::Force(id) = mode {
432	            let Some(variant) = self.get(&id) else {
433	                return Err(KernelSelectionError::UnknownForcedVariant { id });
434	            };
435	            problem.validate(variant).map_err(|rejection| {
436	                KernelSelectionError::IneligibleForcedVariant { id, rejection }
437	            })?;
438	            return Ok(SelectedVariant {
439	                variant,
440	                source: SelectionSource::Override,
441	            });
442	        }
443	
444	        if let Some(cached_id) = cache
445	            .lookup(self.id, problem)
446	            .map_err(KernelSelectionError::CacheLookupFailed)?
447	            && let Some(variant) = self.get(&cached_id)
448	            && problem.validate(variant).is_ok()
449	        {
450	            return Ok(SelectedVariant {
451	                variant,
452	                source: SelectionSource::Cache,
453	            });
454	        }
455	
456	        // Keep automatic selection allocation-free: the family is already a
457	        // fixed array, so compact eligible references into another fixed array
458	        // while preserving declaration order.
459	        let mut eligible: [&KernelVariant<Id, Entry, Meta>; N] =
460	            core::array::from_fn(|index| &self.variants[index]);
461	        let mut eligible_count = 0;
462	        for index in 0..N {
463	            let candidate = eligible[index];
464	            if problem.validate(candidate).is_ok() {
465	                eligible[eligible_count] = candidate;
466	                eligible_count += 1;
467	            }
468	        }
469	        let eligible = &eligible[..eligible_count];
470	        if eligible.is_empty() {
471	            return Err(KernelSelectionError::NoEligibleVariants {
472	                family: self.id,
473	                variant_count: N,
474	            });
475	        }
476	
477	        let selected_id = selector
478	            .select(self.id, problem, eligible)
479	            .map_err(KernelSelectionError::SelectorFailed)?;
480	        let Some(selected) = self.get(&selected_id) else {
481	            return Err(KernelSelectionError::SelectorReturnedUnknownVariant { id: selected_id });
482	        };
483	        if !eligible.iter().any(|variant| variant.id() == &selected_id) {
484	            return Err(KernelSelectionError::SelectorReturnedIneligibleVariant {
485	                id: selected_id,
486	            });
487	        }
488	
489	        cache
490	            .store(self.id, problem, &selected_id)
491	            .map_err(KernelSelectionError::CacheStoreFailed)?;
492	        Ok(SelectedVariant {
493	            variant: selected,
494	            source: SelectionSource::Selector,
495	        })
496	    }
497	}
