45	/// Load a named embedded artifact bundle from the current executable.
46	///
47	/// Cubin and PTX payloads are loaded directly with the CUDA driver. NVVM IR and
48	/// LTOIR payloads are linked to an in-memory cubin for their original target.
49	/// A payload built for a standard pre-Blackwell target, such as `sm_86`, may
50	/// instead be converted to PTX and JIT-compiled by the driver on Blackwell.
51	pub fn load_embedded_module(
52	    ctx: &Arc<CudaContext>,
53	    name: &str,
54	) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
55	    let bundle = artifact_bundles_from_current_exe()?
56	        .into_iter()
57	        .find(|bundle| bundle.name == name)
58	        .ok_or_else(|| EmbeddedModuleError::ModuleNotFound {
59	            name: name.to_string(),
60	        })?;
61	    load_bundle(ctx, &bundle)
62	}
63	
64	/// Merge all PTX bundles from the current executable into a single CUDA module.
65	///
66	/// When a generic kernel is monomorphized in a consuming crate, its PTX ends
67	/// up in that crate's bundle rather than the defining crate's bundle. This
68	/// function gathers every PTX bundle in the binary, strips duplicate header
69	/// directives (`.version`, `.target`, `.address_size`) from all but the first
70	/// bundle, concatenates the bodies, and loads the result as one CUDA module.
71	/// All kernel symbols are therefore available regardless of which crate bundle
72	/// they were compiled into.
73	///
74	/// Bundles with non-PTX payloads (NVVM IR, LTOIR, cubin) are skipped; use
75	/// `load_embedded_module` for those.
76	pub fn load_all_ptx_bundles_merged(
77	    ctx: &Arc<CudaContext>,
78	) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
79	    let bundles = artifact_bundles_from_current_exe()?;
80	
81	    let mut merged = String::new();
82	    let mut found_any = false;
83	
84	    for bundle in &bundles {
85	        if let Some(ptx_bytes) = bundle.payload(ArtifactPayloadKind::Ptx) {
86	            let ptx_str = std::str::from_utf8(ptx_bytes)
87	                .map_err(|_| EmbeddedModuleError::UnsupportedPayload {
88	                    name: bundle.name.clone(),
89	                })?
90	                .trim_end_matches('\0');
91	
92	            if !found_any {
93	                merged.push_str(ptx_str);
94	                merged.push('\n');
95	                found_any = true;
96	            } else {
97	                // Strip per-file header directives; only one set is valid in a
98	                // concatenated PTX module.
99	                for line in ptx_str.lines() {
100	                    let trimmed = line.trim_start();
101	                    if trimmed.starts_with(".version")
102	                        || trimmed.starts_with(".target")
103	                        || trimmed.starts_with(".address_size")
104	                    {
105	                        continue;
106	                    }
107	                    merged.push_str(line);
108	                    merged.push('\n');
109	                }
110	            }
111	        }
112	    }
113	
114	    if !found_any {
115	        return Err(EmbeddedModuleError::NoModules);
116	    }
117	
118	    Ok(ctx.load_module_from_image(merged.as_bytes())?)
119	}
