121	/// Load the first embedded artifact bundle with a supported payload.
122	pub fn load_first_embedded_module(
123	    ctx: &Arc<CudaContext>,
124	) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
125	    for bundle in artifact_bundles_from_current_exe()? {
126	        match load_bundle(ctx, &bundle) {
127	            Ok(module) => return Ok(module),
128	            Err(EmbeddedModuleError::UnsupportedPayload { .. }) => continue,
129	            Err(error) => return Err(error),
130	        }
131	    }
132	    Err(EmbeddedModuleError::NoModules)
133	}
134	
135	fn load_bundle(
136	    ctx: &Arc<CudaContext>,
137	    bundle: &OwnedArtifactBundle,
138	) -> Result<Arc<CudaModule>, EmbeddedModuleError> {
139	    if let Some(cubin) = bundle.payload(ArtifactPayloadKind::Cubin) {
140	        return Ok(ctx.load_module_from_image(cubin)?);
141	    }
142	
143	    if let Some(ptx) = bundle.payload(ArtifactPayloadKind::Ptx) {
144	        return Ok(ctx.load_module_from_image(ptx)?);
145	    }
146	
147	    if let Some(nvvm_ir) = bundle.payload(ArtifactPayloadKind::NvvmIr) {
148	        let emitted = target_arch_for_bundle(bundle)?;
149	        let execution = ltoir::execution_arch_for_context(ctx)?;
150	        let image = match ltoir::execution_route(&emitted, &execution)? {
151	            ltoir::ExecutionRoute::Cubin => {
152	                ltoir::build_cubin_from_nvvm_ir(nvvm_ir, &bundle.name, &emitted.sm())?
153	            }
154	            ltoir::ExecutionRoute::PtxBridge => {
155	                ltoir::build_ptx_from_nvvm_ir(nvvm_ir, &bundle.name, &emitted.sm())?
156	            }
157	        };
158	        return Ok(ctx.load_module_from_image(&image)?);
159	    }
160	
161	    if let Some(ltoir) = bundle.payload(ArtifactPayloadKind::Ltoir) {
162	        let emitted = target_arch_for_bundle(bundle)?;
163	        let execution = ltoir::execution_arch_for_context(ctx)?;
164	        let image = match ltoir::execution_route(&emitted, &execution)? {
165	            ltoir::ExecutionRoute::Cubin => {
166	                ltoir::link_ltoir_to_cubin(ltoir, &bundle.name, &emitted.sm())?
167	            }
168	            ltoir::ExecutionRoute::PtxBridge => {
169	                ltoir::link_ltoir_to_ptx(ltoir, &bundle.name, &emitted.sm())?
170	            }
171	        };
172	        return Ok(ctx.load_module_from_image(&image)?);
173	    }
174	
175	    Err(EmbeddedModuleError::UnsupportedPayload {
176	        name: bundle.name.clone(),
177	    })
178	}
