6	//! Stable 128-bit type identifiers for kernel PTX naming.
7	//!
8	//! The host needs to compute the same per-type hash that the backend computes
9	//! via `tcx.type_id_hash(ty).as_u128()`. The stable [`core::any::TypeId::of`]
10	//! API would force a `T: 'static` bound on the kernel marker, which would in
11	//! turn reject perfectly valid non-`'static` borrowing closures (e.g. a kernel
12	//! launcher capturing `&[f32]` from a stack frame the caller keeps alive
13	//! across the launch). The `core::intrinsics::type_id` form has bound
14	//! `T: ?Sized` — i.e. no `'static` requirement — and produces the exact same
15	//! 128-bit value that `tcx.type_id_hash` does for that type, because both go
16	//! through the same `erase_and_anonymize_regions` + stable-hash pipeline.
17	//!
18	//! The macro layer calls [`type_id_u128_of_val`] with a concrete kernel
19	//! function item. A function item's type contains its definition identity and
20	//! every monomorphized type and const argument, so one hash covers the complete
21	//! specialization without inventing a parallel encoding for const values.
22	//!
23	//! Framing note for future contributors: `core::intrinsics::type_id` is an
24	//! internal API and requires `#![feature(core_intrinsics)]` on the owning
25	//! crate. cuda-oxide already ships against `rustc_private` and pins a
26	//! nightly toolchain, so this is inside our existing risk surface — but the
27	//! helper cannot be lifted into a stable-feeling utility crate without
28	//! re-introducing the feature gate there.
29	
30	use core::any::TypeId;
31	use std::{
32	    collections::HashMap,
33	    sync::{Mutex, OnceLock},
34	};
35	
36	type KernelNameKey = (&'static str, u128);
37	
38	static GENERIC_KERNEL_NAMES: OnceLock<Mutex<HashMap<KernelNameKey, &'static str>>> =
39	    OnceLock::new();
40	
41	/// Returns the same 128-bit hash that the cuda-oxide backend uses for
42	/// kernel export names.
43	///
44	/// At runtime the value is just the 16 raw hash bytes (see the layout
45	/// comment in `core::any::TypeId`). The intrinsic is const-evaluated by
46	/// rustc using its internal `Ty<'tcx>` representation, so the call site
47	/// only ever sees a constant `u128`.
48	///
49	/// Bound is intentionally `T: ?Sized` (not `T: 'static`). The typed launch
50	/// path must keep accepting non-`'static` borrowing closures, the same way
51	/// the legacy `type_name`-based path did. Adding `'static` here would
52	/// silently tighten the typed API without enforcing the actual launch-
53	/// outlives-borrow invariant — that responsibility still sits with the
54	/// caller (the borrow must outlive `stream.synchronize()`).
55	#[inline]
56	pub fn type_id_u128<T: ?Sized>() -> u128 {
57	    let id = const { core::intrinsics::type_id::<T>() };
58	    unsafe { core::mem::transmute::<TypeId, u128>(id) }
59	}
60	
61	/// Returns [`type_id_u128`] for the inferred type of `value`.
62	///
63	/// This is primarily useful for function items, whose anonymous type cannot be
64	/// written in a turbofish. For example, `type_id_u128_of_val(&kernel::<T, 4>)`
65	/// hashes the concrete `kernel::<T, 4>` function-item type rather than its
66	/// coerced function-pointer signature. Keeping the item uncoerced is important:
67	/// the item type retains both the function definition and its generic arguments.
68	#[inline]
69	pub fn type_id_u128_of_val<T: ?Sized>(_: &T) -> u128 {
70	    type_id_u128::<T>()
71	}
72	
73	/// Interns the PTX lookup name for one generic kernel specialization.
74	///
75	/// This is public only because `#[kernel]` expansions in downstream crates
76	/// call it. The process-wide table allocates once per `(base_name, type_hash)`
77	/// pair; repeated launches reuse the same `&'static str` instead of leaking a
78	/// fresh formatted name on every cache lookup.
79	#[doc(hidden)]
80	pub fn __intern_generic_kernel_name(base_name: &'static str, type_hash: u128) -> &'static str {
81	    let names = GENERIC_KERNEL_NAMES.get_or_init(|| Mutex::new(HashMap::new()));
82	    let mut names = names
83	        .lock()
84	        .unwrap_or_else(|poisoned| poisoned.into_inner());
85	    match names.entry((base_name, type_hash)) {
86	        std::collections::hash_map::Entry::Occupied(entry) => entry.get(),
87	        std::collections::hash_map::Entry::Vacant(entry) => {
88	            let name: &'static str =
89	                Box::leak(format!("{base_name}_TID_{type_hash:032x}").into_boxed_str());
90	            entry.insert(name);
91	            name
92	        }
93	    }
94	}
95	
96	#[cfg(test)]
97	mod tests {
98	    use super::*;
99	
100	    #[test]
101	    fn distinct_types_hash_distinctly() {
102	        assert_ne!(type_id_u128::<f32>(), type_id_u128::<i32>());
103	        assert_ne!(type_id_u128::<u32>(), type_id_u128::<i32>());
104	    }
105	
106	    #[test]
107	    fn same_type_hashes_stably() {
108	        let a = type_id_u128::<f32>();
109	        let b = type_id_u128::<f32>();
110	        assert_eq!(a, b);
111	    }
112	
113	    #[test]
114	    fn static_borrow_collides_with_free_borrow() {
115	        // Confirms erase_and_anonymize_regions: free lifetimes (including
116	        // 'static) all hash to the same value. The `'a` is intentionally a
117	        // free lifetime here, used only in the body's turbofish.
118	        #[allow(clippy::extra_unused_lifetimes)]
119	        fn free<'a>() -> u128 {
120	            type_id_u128::<&'a i32>()
121	        }
122	        assert_eq!(type_id_u128::<&'static i32>(), free());
123	    }
124	
125	    #[test]
126	    fn distinct_closure_literals_hash_distinctly() {
127	        let factor = 2.5f32;
128	        let cl1 = move |x: f32| x * factor;
129	        let cl2 = move |x: f32| x * factor;
130	        fn id<T>(_: &T) -> u128 {
131	            type_id_u128::<T>()
132	        }
133	        assert_ne!(id(&cl1), id(&cl2));
134	    }
135	
136	    #[test]
137	    fn function_item_hash_includes_const_arguments() {
138	        fn const_item<const N: usize>() {}
139	
140	        assert_ne!(
141	            type_id_u128_of_val(&const_item::<0>),
142	            type_id_u128_of_val(&const_item::<1>)
143	        );
144	        assert_ne!(
145	            type_id_u128_of_val(&const_item::<4>),
146	            type_id_u128_of_val(&const_item::<8>)
147	        );
148	        assert_eq!(
149	            type_id_u128_of_val(&const_item::<4>),
150	            type_id_u128_of_val(&const_item::<4>)
151	        );
152	    }
153	
154	    #[test]
155	    fn function_item_hash_includes_mixed_type_and_const_arguments() {
156	        fn mixed_item<T, const N: usize>() {}
157	
158	        assert_ne!(
159	            type_id_u128_of_val(&mixed_item::<u32, 4>),
160	            type_id_u128_of_val(&mixed_item::<u32, 8>)
161	        );
162	        assert_ne!(
163	            type_id_u128_of_val(&mixed_item::<u32, 4>),
164	            type_id_u128_of_val(&mixed_item::<i32, 4>)
165	        );
166	    }
167	
168	    #[test]
169	    fn function_item_hash_handles_all_stable_const_parameter_kinds() {
170	        fn primitive_item<const FLAG: bool, const TAG: char, const BYTE: u8>() {}
171	
172	        let base = type_id_u128_of_val(&primitive_item::<false, 'a', 0>);
173	        assert_ne!(base, type_id_u128_of_val(&primitive_item::<true, 'a', 0>));
174	        assert_ne!(base, type_id_u128_of_val(&primitive_item::<false, 'b', 0>));
175	        assert_ne!(base, type_id_u128_of_val(&primitive_item::<false, 'a', 1>));
176	    }
177	
178	    #[test]
179	    fn generic_kernel_names_are_allocated_once_per_specialization() {
180	        let first = __intern_generic_kernel_name("tile", 4);
181	        let repeated = __intern_generic_kernel_name("tile", 4);
182	        let other_const = __intern_generic_kernel_name("tile", 8);
183	        let other_kernel = __intern_generic_kernel_name("reduce", 4);
184	
185	        assert!(core::ptr::eq(first, repeated));
186	        assert_eq!(first, "tile_TID_00000000000000000000000000000004");
187	        assert_ne!(first, other_const);
188	        assert_ne!(first, other_kernel);
189	    }
190	}
