4	//! `#[derive(DeviceCopy)]` proc-macro.
5	//!
6	//! Emits the `unsafe impl DeviceCopy` plus a hidden field-type-check function
7	//! that fails to compile if any field is not itself `DeviceCopy`.
8	
9	use proc_macro2::{Ident, Span, TokenStream};
10	use quote::quote;
11	use syn::{
12	    Data, DataStruct, DataUnion, DeriveInput, Field, Fields, Generics, TypeParamBound, parse_str,
13	};
14	
15	pub fn impl_device_copy(input: &DeriveInput, import: TokenStream) -> TokenStream {
16	    let input_type = &input.ident;
17	
18	    // Generate the code to type-check all fields of the derived struct/union. We can't perform
19	    // type checking at expansion-time, so instead we generate a dummy nested function with a
20	    // type-bound on DeviceCopy and call it with every type that's in the struct/union.
21	    // This will fail to compile if any of the nested types doesn't implement DeviceCopy.
22	    //
23	    // Enums are deliberately rejected: `DeviceCopy`'s safety contract requires
24	    // every bit pattern, including the all-zero pattern written by
25	    // `DeviceBuffer::zeroed`, to be a valid value of the type. That holds for
26	    // product types (structs/unions) when every field is `DeviceCopy`, but NOT
27	    // for enums, whose discriminant leaves most byte patterns invalid. A zeroed
28	    // or device-written buffer could then materialize an out-of-range
29	    // discriminant (undefined behavior). This is the same reason `bool`, `char`,
30	    // and `NonZeroU32` are not `DeviceCopy`. Per-field checking is necessary but
31	    // not sufficient for enums, so we refuse rather than emit an unsound impl.
32	    let check_types_code = match input.data {
33	        Data::Struct(ref data_struct) => type_check_struct(data_struct),
34	        Data::Union(ref data_union) => type_check_union(data_union),
35	        Data::Enum(_) => {
36	            return syn::Error::new_spanned(
37	                input_type,
38	                "`#[derive(DeviceCopy)]` cannot be applied to enums: `DeviceCopy` requires \
39	                 every bit pattern (including the all-zero pattern written by \
40	                 `DeviceBuffer::zeroed`) to be a valid value, but an enum's discriminant \
41	                 leaves most byte patterns invalid, so a zeroed or device-written buffer \
42	                 could materialize an out-of-range discriminant (undefined behavior). If you \
43	                 can guarantee every device-produced byte pattern is a valid variant, write \
44	                 `unsafe impl DeviceCopy for ... {}` by hand.",
45	            )
46	            .to_compile_error();
47	        }
48	    };
49	
50	    // We need a function for the type-checking code to live in, so generate a complicated and
51	    // hopefully-unique name for that. The type identifier is used verbatim (not lowercased) so
52	    // distinct types differing only in case (e.g. `Foo` and `foo`) get distinct helper names
53	    // instead of colliding; the `non_snake_case` allow covers the casing.
54	    let type_test_func_name = format!("__verify_{input_type}_can_implement_devicecopy");
55	    let type_test_func_ident = Ident::new(&type_test_func_name, Span::call_site());
56	
57	    // If the struct/enum/union is generic, we need to add the DeviceCopy bound to the generics
58	    // when implementing DeviceCopy.
59	    let generics = add_bound_to_generics(&input.generics, import.clone());
60	    let (impl_generics, type_generics, where_clause) = generics.split_for_impl();
61	
62	    // Finally, generate the unsafe impl and the type-checking function.
63	    let generated_code = quote! {
64	        unsafe impl #impl_generics #import for #input_type #type_generics #where_clause {}
65	
66	        #[doc(hidden)]
67	        #[allow(non_snake_case, dead_code, unused_variables)]
68	        fn #type_test_func_ident #impl_generics(value: &#input_type #type_generics) #where_clause {
69	            fn assert_impl<T: #import>() {}
70	            #check_types_code
71	        }
72	    };
73	
74	    generated_code
75	}
76	
77	fn add_bound_to_generics(generics: &Generics, import: TokenStream) -> Generics {
78	    let mut new_generics = generics.clone();
79	    let bound: TypeParamBound = parse_str(&quote! {#import}.to_string()).unwrap();
80	
81	    for type_param in &mut new_generics.type_params_mut() {
82	        type_param.bounds.push(bound.clone())
83	    }
84	
85	    new_generics
86	}
87	
88	fn type_check_struct(s: &DataStruct) -> TokenStream {
89	    let checks = match s.fields {
90	        Fields::Named(ref named_fields) => {
91	            let fields: Vec<&Field> = named_fields.named.iter().collect();
92	            check_fields(&fields)
93	        }
94	        Fields::Unnamed(ref unnamed_fields) => {
95	            let fields: Vec<&Field> = unnamed_fields.unnamed.iter().collect();
96	            check_fields(&fields)
97	        }
98	        Fields::Unit => vec![],
99	    };
100	    quote!(
101	        #(#checks)*
102	    )
103	}
104	
105	fn type_check_union(s: &DataUnion) -> TokenStream {
106	    let fields: Vec<&Field> = s.fields.named.iter().collect();
107	    let checks = check_fields(&fields);
108	    quote!(
109	        #(#checks)*
110	    )
111	}
112	
113	fn check_fields(fields: &[&Field]) -> Vec<TokenStream> {
114	    fields
115	        .iter()
116	        .map(|field| {
117	            let field_type = &field.ty;
118	            quote! {assert_impl::<#field_type>();}
119	        })
120	        .collect()
121	}
