6	//! GPU printf procedural macro implementation.
7	//!
8	//! Translates Rust-style format strings to C-style and generates
9	//! argument packing code for CUDA's vprintf.
10	//!
11	//! # Design
12	//!
13	//! The `gpu_printf!` macro:
14	//! 1. Parses Rust-style format string (`{}`, `{:x}`, `{:.2}`, etc.)
15	//! 2. Translates to C format string (`%d`, `%x`, `%.2f`, etc.)
16	//! 3. Generates a `#[repr(C)]` struct for argument packing
17	//! 4. Calls `__gpu_vprintf(format_ptr, args_ptr)` which the compiler recognizes
18	//!
19	//! # C Vararg Promotion Rules
20	//!
21	//! Arguments are promoted following C vararg rules:
22	//! - `i8`, `i16` → `i32`
23	//! - `u8`, `u16` → `u32`
24	//! - `f32` → `f64` (critical!)
25	//! - `bool` → `i32` (0 or 1)
26	//! - pointers/references → `u64` (64-bit)
27	
28	use proc_macro2::TokenStream as TokenStream2;
29	use quote::{format_ident, quote};
30	use syn::{
31	    Expr, LitStr, Token,
32	    parse::{Parse, ParseStream},
33	};
34	
35	/// Maximum number of printf arguments (CUDA limitation)
36	const MAX_PRINTF_ARGS: usize = 32;
37	
38	/// Input to gpu_printf! macro: format string followed by arguments
39	pub struct GpuPrintfInput {
40	    format_string: LitStr,
41	    args: Vec<Expr>,
42	}
43	
44	impl Parse for GpuPrintfInput {
45	    fn parse(input: ParseStream) -> syn::Result<Self> {
46	        let format_string: LitStr = input.parse()?;
47	        let mut args = Vec::new();
48	
49	        while input.peek(Token![,]) {
50	            input.parse::<Token![,]>()?;
51	            if !input.is_empty() {
52	                args.push(input.parse()?);
53	            }
54	        }
55	
56	        Ok(GpuPrintfInput {
57	            format_string,
58	            args,
59	        })
60	    }
61	}
62	
63	/// Parsed format placeholder from the format string
64	#[derive(Debug, Clone)]
65	struct Placeholder {
66	    /// Start position in format string (at the `{`)
67	    start: usize,
68	    /// End position in format string (after the `}`)
69	    end: usize,
70	    /// Parsed format specification
71	    spec: FormatSpec,
72	}
73	
74	/// Format specification parsed from `{:...}`
75	#[derive(Debug, Clone, Default)]
76	struct FormatSpec {
77	    /// `-` flag: left-justify
78	    left_justify: bool,
79	    /// `+` flag: always show sign
80	    always_sign: bool,
81	    /// ` ` flag: space before positive numbers
82	    space_sign: bool,
83	    /// `#` flag: alternate form (0x prefix for hex, etc.)
84	    alternate: bool,
85	    /// `0` flag: zero-pad
86	    zero_pad: bool,
87	    /// Minimum width (None = no width specified)
88	    width: Option<Width>,
89	    /// Precision (None = no precision specified)
90	    precision: Option<Precision>,
91	    /// Format type character (x, X, o, e, E, f, g, G, a, A, p, c, s, d, etc.)
92	    format_type: Option<char>,
93	}
94	
95	/// Width specification
96	#[derive(Debug, Clone)]
97	enum Width {
98	    /// Literal width value
99	    Literal(usize),
100	    /// Runtime width (`*`)
101	    Runtime,
102	}
103	
104	/// Precision specification
105	#[derive(Debug, Clone)]
106	enum Precision {
107	    /// Literal precision value
108	    Literal(usize),
109	    /// Runtime precision (`.*`)
110	    Runtime,
111	}
112	
113	/// Parse all placeholders from a format string
114	fn parse_format_string(format: &str) -> Result<Vec<Placeholder>, String> {
115	    let mut placeholders = Vec::new();
116	    let chars: Vec<char> = format.chars().collect();
117	    let mut i = 0;
118	
119	    while i < chars.len() {
120	        if chars[i] == '{' {
121	            if i + 1 < chars.len() && chars[i + 1] == '{' {
122	                // Escaped `{{` - literal `{`
123	                i += 2;
124	                continue;
125	            }
126	
127	            // Found a placeholder
128	            let start = i;
129	            i += 1; // Skip `{`
130	
131	            // Parse until `}`
132	            let mut spec = FormatSpec::default();
133	
134	            while i < chars.len() && chars[i] != '}' {
135	                if chars[i] == ':' {
136	                    i += 1;
137	                    // Parse format spec after `:`
138	                    i = parse_format_spec(&chars, i, &mut spec)?;
139	                } else {
140	                    i += 1;
141	                }
142	            }
143	
144	            if i >= chars.len() {
145	                return Err("Unclosed format placeholder `{`".to_string());
146	            }
147	
148	            i += 1; // Skip `}`
149	
150	            placeholders.push(Placeholder {
151	                start,
152	                end: i,
153	                spec,
154	            });
155	        } else if chars[i] == '}' {
156	            if i + 1 < chars.len() && chars[i + 1] == '}' {
157	                // Escaped `}}` - literal `}`
158	                i += 2;
159	                continue;
160	            }
161	            return Err("Unmatched `}` in format string".to_string());
162	        } else {
163	            i += 1;
164	        }
165	    }
166	
167	    Ok(placeholders)
168	}
169	
170	/// Parse format specification after the `:` in `{:...}`
171	fn parse_format_spec(chars: &[char], mut i: usize, spec: &mut FormatSpec) -> Result<usize, String> {
172	    // Parse flags
173	    while i < chars.len() && chars[i] != '}' {
174	        match chars[i] {
175	            '-' => {
176	                spec.left_justify = true;
177	                i += 1;
178	            }
179	            '+' => {
180	                spec.always_sign = true;
181	                i += 1;
182	            }
183	            ' ' => {
184	                spec.space_sign = true;
185	                i += 1;
186	            }
187	            '#' => {
188	                spec.alternate = true;
189	                i += 1;
190	            }
191	            '0' if spec.width.is_none() => {
192	                // Leading 0 is zero-pad flag, not part of width
193	                spec.zero_pad = true;
194	                i += 1;
195	            }
196	            _ => break,
197	        }
198	    }
199	
200	    // Parse width
201	    if i < chars.len() && chars[i] != '}' {
202	        if chars[i] == '*' {
203	            spec.width = Some(Width::Runtime);
204	            i += 1;
205	        } else if chars[i].is_ascii_digit() {
206	            let (width, new_i) = parse_number(chars, i);
207	            spec.width = Some(Width::Literal(width));
208	            i = new_i;
209	        }
210	    }
211	
212	    // Parse precision
213	    if i < chars.len() && chars[i] == '.' {
214	        i += 1; // Skip `.`
215	        if i < chars.len() {
216	            if chars[i] == '*' {
217	                spec.precision = Some(Precision::Runtime);
218	                i += 1;
219	            } else if chars[i].is_ascii_digit() {
220	                let (prec, new_i) = parse_number(chars, i);
221	                spec.precision = Some(Precision::Literal(prec));
222	                i = new_i;
223	            } else {
224	                // `.` without number means precision 0
225	                spec.precision = Some(Precision::Literal(0));
226	            }
227	        }
228	    }
229	
230	    // Parse type character
231	    if i < chars.len() && chars[i] != '}' {
232	        let c = chars[i];
233	        if matches!(
234	            c,
235	            'c' | 's'
236	                | 'd'
237	                | 'i'
238	                | 'o'
239	                | 'x'
240	                | 'X'
241	                | 'e'
242	                | 'E'
243	                | 'f'
244	                | 'g'
245	                | 'G'
246	                | 'a'
247	                | 'A'
248	                | 'p'
249	                | 'b'
250	        ) {
251	            spec.format_type = Some(c);
252	            i += 1;
253	        }
254	    }
255	
256	    Ok(i)
257	}
258	
259	/// Parse a decimal number from the character array
260	fn parse_number(chars: &[char], mut i: usize) -> (usize, usize) {
261	    let mut num = 0usize;
262	    while i < chars.len() && chars[i].is_ascii_digit() {
263	        num = num * 10 + (chars[i] as usize - '0' as usize);
264	        i += 1;
265	    }
266	    (num, i)
267	}
268	
269	/// Count how many extra arguments are needed for runtime width/precision
270	fn count_runtime_args(spec: &FormatSpec) -> usize {
271	    let mut count = 0;
272	    if matches!(spec.width, Some(Width::Runtime)) {
273	        count += 1;
274	    }
275	    if matches!(spec.precision, Some(Precision::Runtime)) {
276	        count += 1;
277	    }
278	    count
279	}
