281	/// Build the C format string from Rust format string
282	fn build_c_format_string(format: &str, placeholders: &[Placeholder]) -> String {
283	    let mut result = String::new();
284	    let chars: Vec<char> = format.chars().collect();
285	    let mut last_end = 0;
286	
287	    for placeholder in placeholders {
288	        // Add literal text before this placeholder
289	        let mut i = last_end;
290	        while i < placeholder.start {
291	            if chars[i] == '{' && i + 1 < chars.len() && chars[i + 1] == '{' {
292	                result.push('{');
293	                i += 2;
294	            } else if chars[i] == '}' && i + 1 < chars.len() && chars[i + 1] == '}' {
295	                result.push('}');
296	                i += 2;
297	            } else if chars[i] == '%' {
298	                // Escape literal % as %%
299	                result.push_str("%%");
300	                i += 1;
301	            } else {
302	                result.push(chars[i]);
303	                i += 1;
304	            }
305	        }
306	
307	        // Add placeholder as %... (will be filled in by generate_c_specifier)
308	        // For now, add a marker that we'll replace
309	        result.push_str("__PLACEHOLDER__");
310	
311	        last_end = placeholder.end;
312	    }
313	
314	    // Add remaining literal text
315	    let mut i = last_end;
316	    while i < chars.len() {
317	        if chars[i] == '{' && i + 1 < chars.len() && chars[i + 1] == '{' {
318	            result.push('{');
319	            i += 2;
320	        } else if chars[i] == '}' && i + 1 < chars.len() && chars[i + 1] == '}' {
321	            result.push('}');
322	            i += 2;
323	        } else if chars[i] == '%' {
324	            result.push_str("%%");
325	            i += 1;
326	        } else {
327	            result.push(chars[i]);
328	            i += 1;
329	        }
330	    }
331	
332	    result
333	}
334	
335	/// Generate C format specifier from FormatSpec.
336	fn generate_c_specifier(
337	    spec: &FormatSpec,
338	    is_64bit: bool,
339	    is_float: bool,
340	    is_string: bool,
341	) -> String {
342	    let mut result = String::from("%");
343	
344	    // Add flags
345	    if spec.left_justify {
346	        result.push('-');
347	    }
348	    if spec.always_sign {
349	        result.push('+');
350	    }
351	    if spec.space_sign {
352	        result.push(' ');
353	    }
354	    if spec.alternate {
355	        result.push('#');
356	    }
357	    if spec.zero_pad {
358	        result.push('0');
359	    }
360	
361	    // Add width
362	    match &spec.width {
363	        Some(Width::Literal(w)) => result.push_str(&w.to_string()),
364	        Some(Width::Runtime) => result.push('*'),
365	        None => {}
366	    }
367	
368	    // Add precision
369	    match &spec.precision {
370	        Some(Precision::Literal(p)) => {
371	            result.push('.');
372	            result.push_str(&p.to_string());
373	        }
374	        Some(Precision::Runtime) => result.push_str(".*"),
375	        None => {}
376	    }
377	
378	    // Add size modifier for 64-bit integers
379	    if is_64bit && !is_float && !is_string {
380	        result.push_str("ll");
381	    }
382	
383	    // Add type character
384	    let type_char = match spec.format_type {
385	        Some('c') => 'c',
386	        Some('s') => 's',
387	        Some('d') | Some('i') => 'd',
388	        Some('o') => 'o',
389	        Some('x') => 'x',
390	        Some('X') => 'X',
391	        Some('e') => 'e',
392	        Some('E') => 'E',
393	        Some('f') => 'f',
394	        Some('g') => 'g',
395	        Some('G') => 'G',
396	        Some('a') => 'a',
397	        Some('A') => 'A',
398	        Some('p') => 'p',
399	        Some('b') => 'b', // Binary - we'll handle this specially
400	        Some(_) => {
401	            // Unknown format specifier - fall back to default
402	            if is_string {
403	                's'
404	            } else if is_float {
405	                'f'
406	            } else {
407	                'd'
408	            }
409	        }
410	        None => {
411	            // Default type based on argument type
412	            if is_string {
413	                's'
414	            } else if is_float {
415	                'f'
416	            } else {
417	                'd' // Will be 'u' for unsigned, handled at arg level
418	            }
419	        }
420	    };
421	    result.push(type_char);
422	
423	    result
424	}
