426	/// Main proc macro implementation (called from lib.rs)
427	pub fn gpu_printf_impl(input: GpuPrintfInput) -> TokenStream2 {
428	    let format_str = input.format_string.value();
429	
430	    // Parse the format string
431	    let placeholders = match parse_format_string(&format_str) {
432	        Ok(p) => p,
433	        Err(e) => {
434	            return syn::Error::new(input.format_string.span(), e).to_compile_error();
435	        }
436	    };
437	
438	    // Count total expected arguments (including runtime width/precision)
439	    let mut expected_args = 0;
440	    for p in &placeholders {
441	        expected_args += 1; // The value itself
442	        expected_args += count_runtime_args(&p.spec);
443	    }
444	
445	    // Validate argument count
446	    if input.args.len() != expected_args {
447	        return syn::Error::new(
448	            input.format_string.span(),
449	            format!(
450	                "format string requires {} arguments but {} were supplied",
451	                expected_args,
452	                input.args.len()
453	            ),
454	        )
455	        .to_compile_error();
456	    }
457	
458	    // Check max args limit
459	    if input.args.len() > MAX_PRINTF_ARGS {
460	        return syn::Error::new(
461	            input.format_string.span(),
462	            format!(
463	                "gpu_printf! supports at most {} arguments, {} were supplied",
464	                MAX_PRINTF_ARGS,
465	                input.args.len()
466	            ),
467	        )
468	        .to_compile_error();
469	    }
470	
471	    // If no arguments, simple case
472	    if placeholders.is_empty() {
473	        let c_format = build_c_format_string(&format_str, &placeholders);
474	        // Create byte string literal for format string (avoids str type)
475	        let format_with_null = format!("{}\0", c_format);
476	        let format_lit =
477	            syn::LitByteStr::new(format_with_null.as_bytes(), proc_macro2::Span::call_site());
478	
479	        return quote! {
480	            {
481	                // No arguments - pass null for args pointer
482	                // Use byte string literal directly (avoids str type which GPU doesn't support)
483	                cuda_device::debug::__gpu_vprintf(
484	                    #format_lit.as_ptr(),
485	                    core::ptr::null()
486	                )
487	            }
488	        };
489	    }
490	
491	    // Generate the argument struct fields and initializers
492	    let mut field_defs: Vec<TokenStream2> = Vec::new();
493	    let mut field_inits: Vec<TokenStream2> = Vec::new();
494	    let mut c_specifiers: Vec<String> = Vec::new();
495	    let mut arg_idx = 0;
496	
497	    for (placeholder_idx, placeholder) in placeholders.iter().enumerate() {
498	        let spec = &placeholder.spec;
499	
500	        // Handle runtime width
501	        if matches!(spec.width, Some(Width::Runtime)) {
502	            let field_name = format_ident!("__width_{}", placeholder_idx);
503	            let arg = &input.args[arg_idx];
504	            field_defs.push(quote! { #field_name: i32 });
505	            field_inits.push(quote! { #field_name: (#arg) as i32 });
506	            arg_idx += 1;
507	        }
508	
509	        // Handle runtime precision
510	        if matches!(spec.precision, Some(Precision::Runtime)) {
511	            let field_name = format_ident!("__prec_{}", placeholder_idx);
512	            let arg = &input.args[arg_idx];
513	            field_defs.push(quote! { #field_name: i32 });
514	            field_inits.push(quote! { #field_name: (#arg) as i32 });
515	            arg_idx += 1;
516	        }
517	
518	        // Handle the value argument
519	        let field_name = format_ident!("__arg_{}", placeholder_idx);
520	        let arg = &input.args[arg_idx];
521	        arg_idx += 1;
522	
523	        // Generate field type and initialization based on format specifier
524	        // Use concrete types - C vararg promotion rules apply:
525	        // - f32 → f64 (always)
526	        // - i8, i16 → i32; u8, u16 → u32
527	        // - i32, u32, i64, u64 → unchanged
528	        // We use i64/u64 as the default to handle all integer sizes safely
529	        let (field_ty, field_init, is_64bit, is_float, is_string) = match spec.format_type {
530	            Some('c') => {
531	                // Character: promote to i32
532	                (
533	                    quote! { i32 },
534	                    quote! { (#arg) as i32 },
535	                    false,
536	                    false,
537	                    false,
538	                )
539	            }
540	            Some('s') => {
541	                // String: pass pointer
542	                (
543	                    quote! { *const u8 },
544	                    quote! { {
545	                        // Ensure string is null-terminated
546	                        const __STR: &str = concat!(#arg, "\0");
547	                        __STR.as_ptr()
548	                    }},
549	                    false,
550	                    false,
551	                    true,
552	                )
553	            }
554	            Some('p') => {
555	                // Pointer
556	                (quote! { u64 }, quote! { (#arg) as u64 }, true, false, false)
557	            }
558	            Some('e') | Some('E') | Some('f') | Some('g') | Some('G') | Some('a') | Some('A') => {
559	                // Float: always promote to f64
560	                (quote! { f64 }, quote! { (#arg) as f64 }, false, true, false)
561	            }
562	            Some('x') | Some('X') | Some('o') | Some('b') => {
563	                // Hex/octal/binary: use u64 to handle all unsigned integer sizes
564	                (quote! { u64 }, quote! { (#arg) as u64 }, true, false, false)
565	            }
566	            Some('d') | Some('i') => {
567	                // Signed integer: use i64 to handle all signed integer sizes
568	                (quote! { i64 }, quote! { (#arg) as i64 }, true, false, false)
569	            }
570	            None => {
571	                // Default format - use i64 for integers (most common case)
572	                // The C format string will be %lld
573	                (quote! { i64 }, quote! { (#arg) as i64 }, true, false, false)
574	            }
575	            _ => {
576	                // Fallback to i64
577	                (quote! { i64 }, quote! { (#arg) as i64 }, true, false, false)
578	            }
579	        };
580	
581	        field_defs.push(quote! { #field_name: #field_ty });
582	        field_inits.push(quote! { #field_name: #field_init });
583	
584	        // Generate C format specifier
585	        // For trait-based types, we use a placeholder that gets resolved at compile time
586	        let c_spec = generate_c_specifier(spec, is_64bit, is_float, is_string);
587	        c_specifiers.push(c_spec);
588	    }
589	
590	    // Build the final C format string
591	    let mut c_format = build_c_format_string(&format_str, &placeholders);
592	    for c_spec in &c_specifiers {
593	        c_format = c_format.replacen("__PLACEHOLDER__", c_spec, 1);
594	    }
595	
596	    // Generate unique struct name
597	    let struct_name = format_ident!("__GpuPrintfArgs");
598	
599	    // Create byte string literal for format string (avoids str type)
600	    let format_with_null = format!("{}\0", c_format);
601	    let format_lit =
602	        syn::LitByteStr::new(format_with_null.as_bytes(), proc_macro2::Span::call_site());
603	
604	    let expanded = quote! {
605	        {
606	            // Argument packing struct with C-compatible layout
607	            #[repr(C)]
608	            struct #struct_name {
609	                #(#field_defs),*
610	            }
611	
612	            // Pack arguments
613	            let __args = #struct_name {
614	                #(#field_inits),*
615	            };
616	
617	            // Call vprintf intrinsic
618	            // Use byte string literal directly (avoids str type which GPU doesn't support)
619	            cuda_device::debug::__gpu_vprintf(
620	                #format_lit.as_ptr(),
621	                &__args as *const #struct_name as *const u8
622	            )
623	        }
624	    };
625	
626	    expanded
627	}
