13	
14	const MAX_PTX_ASM_INPUTS: usize = 16;
15	const REGISTER_ONLY_OPTION: &str = "register_only";
16	const MAY_DIVERGE_OPTION: &str = "may_diverge";
17	const REGISTER_ONLY_MAY_DIVERGE_OPTIONS: &str = "register_only,may_diverge";
18	const SUPPORTED_INPUT_CONSTRAINTS: &[&str] = &["h", "r", "l", "q", "f", "d", "n"];
19	const SUPPORTED_OUTPUT_CONSTRAINTS: &[&str] = &["=h", "=r", "=l", "=q", "=f", "=d"];
20	
21	pub struct PtxAsmInput {
22	    template: LitStr,
23	    operands: Vec<PtxAsmOperand>,
24	}
25	
26	enum PtxAsmOperand {
27	    Out { constraint: LitStr, place: Expr },
28	    In { constraint: LitStr, expr: Expr },
29	    Clobber { name: LitStr },
30	    Options { options: Vec<Ident> },
31	}
32	
33	#[derive(Default)]
34	struct PtxAsmOptions {
35	    register_only: bool,
36	    may_diverge: bool,
37	}
38	
39	impl Parse for PtxAsmInput {
40	    fn parse(input: ParseStream) -> syn::Result<Self> {
41	        let template: LitStr = input.parse()?;
42	        let mut operands = Vec::new();
43	
44	        while input.peek(Token![,]) {
45	            input.parse::<Token![,]>()?;
46	            if input.is_empty() {
47	                break;
48	            }
49	
50	            if input.peek(Token![in]) {
51	                input.parse::<Token![in]>()?;
52	                let constraint = parse_parenthesized_string(input)?;
53	                let expr: Expr = input.parse()?;
54	                operands.push(PtxAsmOperand::In { constraint, expr });
55	                continue;
56	            }
57	
58	            let ident: syn::Ident = input.parse()?;
59	            match ident.to_string().as_str() {
60	                "out" => {
61	                    let constraint = parse_parenthesized_string(input)?;
62	                    let place: Expr = input.parse()?;
63	                    operands.push(PtxAsmOperand::Out { constraint, place });
64	                }
65	                "clobber" => {
66	                    let name = parse_parenthesized_string(input)?;
67	                    operands.push(PtxAsmOperand::Clobber { name });
68	                }
69	                "options" => {
70	                    let options = parse_parenthesized_options(input)?;
71	                    operands.push(PtxAsmOperand::Options { options });
72	                }
73	                other => {
74	                    return Err(syn::Error::new(
75	                        ident.span(),
76	                        format!(
77	                            "unsupported ptx_asm! operand `{other}`; expected `out`, `in`, `clobber`, or `options`"
78	                        ),
79	                    ));
80	                }
81	            }
82	        }
83	
84	        Ok(Self { template, operands })
85	    }
86	}
87	
88	fn parse_parenthesized_string(input: ParseStream) -> syn::Result<LitStr> {
89	    let content;
90	    parenthesized!(content in input);
91	    let lit: LitStr = content.parse()?;
92	    if !content.is_empty() {
93	        return Err(syn::Error::new(
94	            content.span(),
95	            "expected a single string literal in parentheses",
96	        ));
97	    }
98	    Ok(lit)
99	}
100	
101	fn parse_parenthesized_options(input: ParseStream) -> syn::Result<Vec<Ident>> {
102	    let content;
103	    parenthesized!(content in input);
104	    let options: Punctuated<Ident, Token![,]> = Punctuated::parse_terminated(&content)?;
105	    if options.is_empty() {
106	        return Err(syn::Error::new(
107	            content.span(),
108	            "options(...) requires at least one option",
109	        ));
110	    }
111	    Ok(options.into_iter().collect())
112	}
