114	pub fn ptx_asm_impl(input: PtxAsmInput) -> TokenStream2 {
115	    match build_ptx_asm(input) {
116	        Ok(tokens) => tokens,
117	        Err(err) => err.to_compile_error(),
118	    }
119	}
120	
121	fn build_ptx_asm(input: PtxAsmInput) -> syn::Result<TokenStream2> {
122	    let mut output: Option<(LitStr, Expr)> = None;
123	    let mut inputs: Vec<(LitStr, Expr)> = Vec::new();
124	    let mut clobbers: Vec<LitStr> = Vec::new();
125	    let mut options = PtxAsmOptions::default();
126	    let mut saw_input = false;
127	
128	    for operand in input.operands {
129	        match operand {
130	            PtxAsmOperand::Out { constraint, place } => {
131	                if saw_input {
132	                    return Err(syn::Error::new(
133	                        constraint.span(),
134	                        "`out` operands must appear before `in` operands",
135	                    ));
136	                }
137	                if output.is_some() {
138	                    return Err(syn::Error::new(
139	                        constraint.span(),
140	                        "ptx_asm! currently supports at most one `out` operand",
141	                    ));
142	                }
143	                validate_output_constraint(&constraint)?;
144	                output = Some((constraint, place));
145	            }
146	            PtxAsmOperand::In { constraint, expr } => {
147	                validate_input_constraint(&constraint)?;
148	                saw_input = true;
149	                inputs.push((constraint, expr));
150	            }
151	            PtxAsmOperand::Clobber { name } => clobbers.push(name),
152	            PtxAsmOperand::Options {
153	                options: option_idents,
154	            } => {
155	                for option in option_idents {
156	                    match option.to_string().as_str() {
157	                        REGISTER_ONLY_OPTION => {
158	                            if options.register_only {
159	                                return Err(syn::Error::new(
160	                                    option.span(),
161	                                    "`options(register_only)` was specified more than once",
162	                                ));
163	                            }
164	                            options.register_only = true;
165	                        }
166	                        MAY_DIVERGE_OPTION => {
167	                            if options.may_diverge {
168	                                return Err(syn::Error::new(
169	                                    option.span(),
170	                                    "`options(may_diverge)` was specified more than once",
171	                                ));
172	                            }
173	                            options.may_diverge = true;
174	                        }
175	                        other => {
176	                            return Err(syn::Error::new(
177	                                option.span(),
178	                                format!(
179	                                    "unsupported ptx_asm! option `{other}`; expected `register_only` or `may_diverge`"
180	                                ),
181	                            ));
182	                        }
183	                    }
184	                }
185	            }
186	        }
187	    }
188	
189	    if options.register_only && output.is_none() {
190	        return Err(syn::Error::new(
191	            input.template.span(),
192	            "`options(register_only)` requires an `out` operand",
193	        ));
194	    }
195	    if options.register_only && !clobbers.is_empty() {
196	        return Err(syn::Error::new(
197	            clobbers[0].span(),
198	            "`options(register_only)` cannot be used with clobbers",
199	        ));
200	    }
201	    if options.may_diverge && !options.register_only {
202	        return Err(syn::Error::new(
203	            input.template.span(),
204	            "`options(may_diverge)` requires `register_only`",
205	        ));
206	    }
207	
208	    if inputs.len() > MAX_PTX_ASM_INPUTS {
209	        return Err(syn::Error::new(
210	            input.template.span(),
211	            format!("ptx_asm! supports at most {MAX_PTX_ASM_INPUTS} input operands"),
212	        ));
213	    }
214	
215	    let operand_count = usize::from(output.is_some()) + inputs.len();
216	    let converted_template = convert_cuda_template(&input.template, operand_count)?;
217	    let template_lit = syn::LitByteStr::new(converted_template.as_bytes(), input.template.span());
218	
219	    let mut constraints = Vec::new();
220	    if let Some((constraint, _)) = &output {
221	        constraints.push(constraint.value());
222	    }
223	    constraints.extend(inputs.iter().map(|(constraint, _)| constraint.value()));
224	    for clobber in &clobbers {
225	        constraints.push(normalize_clobber(clobber)?);
226	    }
227	    let constraints = constraints.join(",");
228	    let constraints_lit = syn::LitByteStr::new(constraints.as_bytes(), input.template.span());
229	    let options_marker = if options.register_only && options.may_diverge {
230	        REGISTER_ONLY_MAY_DIVERGE_OPTIONS
231	    } else if options.register_only {
232	        REGISTER_ONLY_OPTION
233	    } else {
234	        ""
235	    };
236	    let options_lit = syn::LitByteStr::new(options_marker.as_bytes(), input.template.span());
237	
238	    let input_exprs: Vec<&Expr> = inputs.iter().map(|(_, expr)| expr).collect();
239	    let arity = input_exprs.len();
240	
241	    if let Some((_, place)) = output {
242	        let fn_ident = format_ident!("__ptx_asm_out_{arity}");
243	        Ok(quote! {{
244	            #place = cuda_device::ptx::#fn_ident(
245	                #template_lit,
246	                #constraints_lit,
247	                #options_lit,
248	                #(#input_exprs),*
249	            );
250	        }})
251	    } else {
252	        let fn_ident = format_ident!("__ptx_asm_void_{arity}");
253	        Ok(quote! {{
254	            cuda_device::ptx::#fn_ident(
255	                #template_lit,
256	                #constraints_lit,
257	                #options_lit,
258	                #(#input_exprs),*
259	            );
260	        }})
261	    }
262	}
263	
264	fn convert_cuda_template(template: &LitStr, operand_count: usize) -> syn::Result<String> {
265	    let value = template.value();
266	    let mut converted = String::with_capacity(value.len());
267	    let mut chars = value.chars().peekable();
268	
269	    while let Some(ch) = chars.next() {
270	        if ch == '$' {
271	            converted.push_str("$$");
272	            continue;
273	        }
274	
275	        if ch != '%' {
276	            converted.push(ch);
277	            continue;
278	        }
279	
280	        match chars.peek().copied() {
281	            Some('%') => {
282	                chars.next();
283	                converted.push('%');
284	            }
285	            Some(next) if next.is_ascii_digit() => {
286	                let mut digits = String::new();
287	                converted.push('$');
288	                while let Some(digit) = chars.peek().copied() {
289	                    if digit.is_ascii_digit() {
290	                        chars.next();
291	                        digits.push(digit);
292	                        converted.push(digit);
293	                    } else {
294	                        break;
295	                    }
296	                }
297	                let index = digits.parse::<usize>().map_err(|_| {
298	                    syn::Error::new(
299	                        template.span(),
300	                        format!("ptx_asm! template placeholder `%{digits}` is too large"),
301	                    )
302	                })?;
303	                if index >= operand_count {
304	                    return Err(syn::Error::new(
305	                        template.span(),
306	                        format!(
307	                            "ptx_asm! template placeholder `%{digits}` has no matching operand"
308	                        ),
309	                    ));
310	                }
311	            }
312	            Some(other) => {
313	                let mut literal = String::new();
314	                for ch in chars.clone() {
315	                    if ch.is_ascii_alphanumeric() || matches!(ch, '_' | '.') {
316	                        literal.push(ch);
317	                    } else {
318	                        break;
319	                    }
320	                }
321	                if literal.is_empty() {
322	                    literal.push(other);
323	                }
324	                return Err(syn::Error::new(
325	                    template.span(),
326	                    format!(
327	                        "literal PTX register `%{literal}` must be escaped as `%%{literal}` in ptx_asm!"
328	                    ),
329	                ));
330	            }
331	            None => {
332	                return Err(syn::Error::new(
333	                    template.span(),
334	                    "trailing `%` in ptx_asm! template",
335	                ));
336	            }
337	        }
338	    }
339	
340	    Ok(converted)
341	}
342	
343	fn validate_single_constraint(constraint: &LitStr) -> syn::Result<String> {
344	    let value = constraint.value();
345	    if value.contains(',') {
346	        return Err(syn::Error::new(
347	            constraint.span(),
348	            "ptx_asm! operand constraints cannot contain `,`; use separate operands and clobber(...)",
349	        ));
350	    }
351	    Ok(value)
352	}
353	
354	fn validate_output_constraint(constraint: &LitStr) -> syn::Result<()> {
355	    let value = validate_single_constraint(constraint)?;
356	    if !value.starts_with('=') {
357	        return Err(syn::Error::new(
358	            constraint.span(),
359	            "`out` constraints must use output syntax such as `\"=r\"`",
360	        ));
361	    }
362	    if !SUPPORTED_OUTPUT_CONSTRAINTS.contains(&value.as_str()) {
363	        return Err(syn::Error::new(
364	            constraint.span(),
365	            format!(
366	                "unsupported `out` constraint `{value}`; expected one of {SUPPORTED_OUTPUT_CONSTRAINTS:?}"
367	            ),
368	        ));
369	    }
370	    Ok(())
371	}
372	
373	fn validate_input_constraint(constraint: &LitStr) -> syn::Result<()> {
374	    let value = validate_single_constraint(constraint)?;
375	    if value.starts_with('=') || value.starts_with('+') {
376	        return Err(syn::Error::new(
377	            constraint.span(),
378	            "`in` constraints must use input syntax such as `\"r\"`",
379	        ));
380	    }
381	    if !SUPPORTED_INPUT_CONSTRAINTS.contains(&value.as_str()) {
382	        return Err(syn::Error::new(
383	            constraint.span(),
384	            format!(
385	                "unsupported `in` constraint `{value}`; expected one of {SUPPORTED_INPUT_CONSTRAINTS:?}"
386	            ),
387	        ));
388	    }
389	    Ok(())
390	}
391	
392	fn normalize_clobber(clobber: &LitStr) -> syn::Result<String> {
393	    let value = clobber.value();
394	    if value == "memory" {
395	        Ok("~{memory}".to_string())
396	    } else if value.starts_with("~{") && value.ends_with('}') {
397	        Ok(value)
398	    } else {
399	        Err(syn::Error::new(
400	            clobber.span(),
401	            "only `clobber(\"memory\")` or raw LLVM clobbers like `clobber(\"~{memory}\")` are supported",
402	        ))
403	    }
404	}
